def _parse_env_value(value: str) -> str:
    value = value.strip()
    if len(value) >= 2 and ((value[0] == value[-1] == '"') or (value[0] == value[-1] == "'")):
        value = value[1:-1]
    return value.encode("utf-8").decode("unicode_escape")


def _load_env_file(env_file: str) -> dict:
    env_file = os.path.abspath(env_file)
    if not os.path.isfile(env_file):
        return {}

    env_vars = {}
    with open(env_file, encoding="utf-8") as fh:
        for raw_line in fh:
            line = raw_line.strip()
            if not line or line.startswith("#"):
                continue
            if "=" not in line:
                continue
            key, value = line.split("=", 1)
            key = key.strip()
            if key:
                env_vars[key] = _parse_env_value(value)
    return env_vars


def _resolve_credentials_env_file() -> str:
    return os.path.abspath(_cli_args.env_file)


def _apply_credentials_env_file() -> None:
    """Load .env file into os.environ (keys in the file win over existing values).

    Ensures MODEL_SERVER_PORT, FIREBASE_*, etc. work when running `python model-server.py`
    without shell `source` (which does not reliably export multiline values).
    """
    path = _resolve_credentials_env_file()
    loaded = _load_env_file(path)
    if loaded:
        logging.info(f"Loaded {len(loaded)} env vars from {path}")
    else:
        logging.warning(f"No env vars loaded from {path} (file missing or empty)")
    for key, value in loaded.items():
        if key:
            os.environ[key] = value


_apply_credentials_env_file()


def _env_str(name: str, *, fallback: str | None = None) -> str:
    value = (os.environ.get(name) or fallback or "").strip()
    return value


def _require_env_str(name: str, *, fallback: str | None = None) -> str:
    value = _env_str(name, fallback=fallback)
    if not value:
        env_file = _resolve_credentials_env_file()
        raise RuntimeError(f"Missing required env var {name} (set it in {env_file})")
    return value

