def _get_next_file_index(folder_path):
    """Get the next available file index in Firebase folder."""
    try:
        if not bucket:
            return 1
        
        blobs = list(bucket.list_blobs(prefix=folder_path))
        # Extract numeric indices from .wav files
        indices = []
        for blob in blobs:
            if blob.name.endswith('.wav'):
                try:
                    # Extract the number from the filename
                    filename = os.path.basename(blob.name)
                    index = int(filename.replace('.wav', ''))
                    indices.append(index)
                except (ValueError, AttributeError):
                    continue
        
        if indices:
            return max(indices) + 1
        return 1
    except Exception as e:
        logging.warning(f"Could not get next file index: {e}")
        return 1

def _download_wav_from_firebase(folder: str, file_index: int, verbose: bool = False) -> str:
    """Download a wav from Firebase storage to a local tmp file and return its path."""
    if not bucket:
        raise RuntimeError("Firebase storage bucket not available")

    blob_path = f"{folder}/{int(file_index)}.wav"
    blob = bucket.blob(blob_path)
    if not blob.exists():
        raise RuntimeError(f"Firebase blob does not exist: {blob_path}")

    fd, tmp_path = tempfile.mkstemp(suffix=".wav")
    os.close(fd)
    try:
        blob.download_to_filename(tmp_path)
        if verbose:
            logging.info(f"[_download_wav_from_firebase] Downloaded {blob_path} to {tmp_path}")
        return tmp_path
    except Exception:
        try:
            if os.path.exists(tmp_path):
                os.remove(tmp_path)
        except Exception:
            pass
        raise

def _compute_and_upload_alternatives_in_background(device_key: str, folder: str, file_index: int, entry_id: str, winner_text: str, verbose: bool = False):
    """Background task: compute alternative hypotheses and update the Firebase interaction entry."""
    tmp_wav = None
    try:
        tmp_wav = _download_wav_from_firebase(folder, int(file_index), verbose=verbose)

        # Compute alternatives using the heavier path
        try:
            cand_winner, cand_winner_conf, alternatives = _transcribe_whisper_ct2(
                tmp_wav,
                model_whisper_finetuned,
                verbose=verbose,
                return_confidence=True,
                return_alternatives=True,
            )
        except Exception as e:
            logging.error(f"[validation-bg] Failed to compute alternatives: {e}")
            return

        # If alternatives is not empty, update the interaction entry
        if alternatives:
            updates = {
                "inference_alternative_transcript": alternatives,
            }
            _update_interaction(folder, entry_id, updates, verbose=verbose)
            if verbose:
                logging.info(f"[validation-bg] Updated interaction {entry_id} with {len(alternatives)} alternative(s)")

        # Optionally identify a loser transcript, but do not save it as a separate _l.txt file.
        loser_text = None
        if alternatives:
            for alt in alternatives:
                if (alt.get("text") or "").strip().lower() != (winner_text or "").strip().lower():
                    loser_text = alt.get("text")
                    break

        # Alternatives are persisted inside the Firebase interaction entry above.

    except Exception as e:
        tb = traceback.format_exc()
        logging.error(f"[validation-bg] Error computing alternatives for device_key={device_key}: {e}")
        logging.error(f"[validation-bg] Traceback:\n{tb}")
    finally:
        if tmp_wav:
            try:
                os.remove(tmp_wav)
            except Exception:
                pass

def _upload_to_firebase(audio_path, transcript, folder, verbose=False):
    """Upload audio and transcript to Firebase Storage."""
    try:
        if not bucket:
            logging.warning(f"Firebase storage bucket not available")
            return None, None
        
        # Get next file index
        file_index = _get_next_file_index(folder)
        
        # Upload audio file
        audio_blob_path = f"{folder}/{file_index}.wav"
        audio_blob = bucket.blob(audio_blob_path)
        audio_blob.upload_from_filename(audio_path)
        if verbose: logging.info(f"Uploaded audio to {audio_blob_path}")
        
        # Upload transcript file
        transcript_blob_path = f"{folder}/{file_index}.txt"
        transcript_blob = bucket.blob(transcript_blob_path)
        transcript_blob.upload_from_string(transcript.encode('utf-8'), content_type='text/plain; charset=utf-8')
        if verbose: logging.info(f"Uploaded transcript to {transcript_blob_path}")
        
        return folder, file_index
    
    except Exception as e:
        logging.error(f"Error uploading to Firebase: {e}")
        return None, None


# -----------------------------
# Interactions index (chiara-speech2text_scheme_data schema)
# -----------------------------
def _load_interactions_index(folder: str) -> list:
    """Load the interactions index JSON from Firebase, or return empty list."""
    try:
        if not bucket:
            return []
        blob_path = f"{folder}/data.json"
        blob = bucket.blob(blob_path)
        try:
            data = blob.download_as_bytes().decode("utf-8")
            import json
            parsed = json.loads(data)
            if isinstance(parsed, list):
                return parsed
            # If stored as dict with "data" key (with or without metadata)
            if isinstance(parsed, dict) and "data" in parsed:
                return parsed["data"]
            return []
        except Exception:
            return []
    except Exception as e:
        logging.warning(f"[_load_interactions_index] Failed to load index for folder {folder}: {e}")
        return []

def _save_interactions_index(folder: str, interactions: list, verbose: bool = False):
    """Save the interactions index JSON to Firebase with schema metadata."""
    import json
    try:
        if not bucket:
            logging.warning("[_save_interactions_index] Firebase bucket not available")
            return
        blob_path = f"{folder}/data.json"
        blob = bucket.blob(blob_path)
        payload = json.dumps({
            "schema_version": SCHEMA_VERSION,
            "data": interactions
        }, ensure_ascii=False, indent=2)
        blob.upload_from_string(payload.encode("utf-8"), content_type="application/json; charset=utf-8")
        if verbose:
            logging.info(f"[_save_interactions_index] Saved {len(interactions)} entries to {blob_path} (schema v{SCHEMA_VERSION})")
    except Exception as e:
        logging.error(f"[_save_interactions_index] Failed to save index for folder {folder}: {e}")

def _add_interaction(folder: str, entry: dict, verbose: bool = False):
    """Add a new interaction entry to the Firebase index (thread-safe)."""
    with INTERACTIONS_INDEX_LOCK:
        interactions = _load_interactions_index(folder)
        interactions.append(entry)
        _save_interactions_index(folder, interactions, verbose=verbose)
        if verbose:
            logging.info(f"[_add_interaction] Added entry {entry.get('entry_id')} to {folder}/data.json")

def _update_interaction(folder: str, entry_id: str, updates: dict, verbose: bool = False):
    """Update fields of an existing interaction entry by ID (thread-safe)."""
    with INTERACTIONS_INDEX_LOCK:
        interactions = _load_interactions_index(folder)
        for entry in interactions:
            if entry.get("entry_id") == entry_id:
                entry.update(updates)
                _save_interactions_index(folder, interactions, verbose=verbose)
                if verbose:
                    logging.info(f"[_update_interaction] Updated entry {entry_id} in {folder}/data.json")
                return
        logging.warning(f"[_update_interaction] Entry {entry_id} not found in {folder}/data.json")

def _build_entry_entry(entry_id: str, timestamp: str, audio_file: str,
                             audio_duration: float, transcript: str, confidence: float,
                             model_version: str, user_validated: bool = False,
                             alternatives: list = None, audio_source: str = "dgx") -> dict:
    """Build a chiara-speech2text_scheme_data-compliant entry dict."""
    # Validate audio_source is one of the allowed values
    if audio_source not in ("whatsapp", "frontend", "dgx"):
        audio_source = "dgx"
    
    entry = {
        "entry_id": entry_id,
        "entry_timestamp": timestamp,
        "audio_data": audio_file,
        "audio_source": audio_source,
        "audio_duration": round(audio_duration, 3),
        "inference_transcript": transcript,
        "inference_confidence": round(confidence, 2),
        "inference_model_version": model_version,
        "inference_alternative_transcript": alternatives or [],
        "user_validated": user_validated,
        "reviewer_is_reviewed": False,
        "reviewer_corrected_transcript": "",
    }
    return entry
