def _looks_like_ct2_dir(path: str) -> bool:
    return (
        os.path.isdir(path)
        and os.path.exists(os.path.join(path, "model.bin"))
        and os.path.exists(os.path.join(path, "config.json"))
    )

def _looks_like_transformers_weights_dir(path: str) -> bool:
    if not os.path.isdir(path):
        return False
    weight_files = [
        "pytorch_model.bin",
        "model.safetensors",
        "tf_model.h5",
        "model.ckpt.index",
        "flax_model.msgpack",
    ]
    return any(os.path.exists(os.path.join(path, f)) for f in weight_files)

model_whisper_finetuned = None
model_whisper_finetuned_pt = None
processor_whisper_finetuned = None

try:
    # Prefer ct2 if the provided path already points to a ct2 directory.
    if _looks_like_ct2_dir(path_whisper_finetuned):
        from faster_whisper import WhisperModel

        logging.info(f"Loading ct2 model from: {path_whisper_finetuned}...")
        model_whisper_finetuned = WhisperModel(
            path_whisper_finetuned,
            device=device,
            compute_type=compute_type,
        )
        logging.info("Successfully loaded ct2 model")
    else:
        # If path is a local folder but doesn't contain transformer weights, skip the PyTorch attempt
        # to avoid confusing logs when the folder is actually a ct2 export.
        try_pytorch = True
        if os.path.isdir(path_whisper_finetuned) and not _looks_like_transformers_weights_dir(path_whisper_finetuned):
            try_pytorch = False

        if try_pytorch:
            from transformers import WhisperForConditionalGeneration, WhisperProcessor

            logging.info(f"Loading PyTorch model from: {path_whisper_finetuned}...")
            model_whisper_finetuned_pt = WhisperForConditionalGeneration.from_pretrained(path_whisper_finetuned)
            processor_whisper_finetuned = WhisperProcessor.from_pretrained(path_whisper_finetuned)
            model_whisper_finetuned_pt.to(device)
            model_whisper_finetuned = "pytorch_fallback"
            logging.info("Successfully loaded PyTorch model")

        # Fallback: try ct2 model next to the base path (common naming convention).
        if model_whisper_finetuned is None:
            logging.info("Attempting to load ct2 model as fallback...")

            ct2_candidates = []
            if path_whisper_finetuned.endswith("-ct2"):
                ct2_candidates.append(path_whisper_finetuned)
            ct2_candidates.append(path_whisper_finetuned + "-ct2")

            ct2_loaded = False
            for ct2_path in ct2_candidates:
                if not _looks_like_ct2_dir(ct2_path):
                    continue
                from faster_whisper import WhisperModel

                logging.info(f"Loading ct2 model from: {ct2_path}...")
                model_whisper_finetuned = WhisperModel(
                    ct2_path,
                    device=device,
                    compute_type=compute_type,
                )
                logging.info("Successfully loaded ct2 model")
                ct2_loaded = True
                break

            if not ct2_loaded:
                raise RuntimeError(
                    "Could not load Whisper model. "
                    f"Expected a Transformers weights directory at '{path_whisper_finetuned}' "
                    "or a CTranslate2 export directory containing 'model.bin' + 'config.json' at one of: "
                    + ", ".join(f"'{p}'" for p in ct2_candidates)
                )

except Exception as e:
    model_whisper_finetuned = None
    tb = traceback.format_exc()
    logging.error(f"Failed to load Whisper model: {e}")
    logging.error(f"Traceback:\n{tb}")
    logging.error(f"Exiting")
    exit(1)

