def _process_wavfile(wav, verbose=False):
    # store received file for processing
    try:
        fd, wav_file = tempfile.mkstemp()
        os.close(fd)
        
        with open(wav_file, "wb") as buffer:
            shutil.copyfileobj(wav.file, buffer)
        
        if verbose: logging.info(f"[_process_input_wavfile] Received audio file. Converted '{wav.filename}' to '{wav_file}'. Now transcribing...")
        return wav_file
    
    except Exception as e:
        tb = traceback.format_exc()
        logging.error(f"[_process_input_wavfile] Error: {e}")
        logging.error(f"[_process_input_wavfile] Traceback:\n{tb}")

        # Attempt safe removal of temporary file
        try:
            if os.path.exists(wav_file):    os.remove(wav_file)
        except Exception as re:
            logging.warning(f"[_process_input_wavfile] Failed to remove tmp file {wav_file}: {re}")
            
        # raise exception
        raise e

def _transcribe_whisper_ct2(wav_file, model, verbose=False, return_confidence=False, return_alternatives=False):
    """Fast transcription path with optional alternative hypotheses.

    If return_confidence=True, returns (text, confidence_pct).
    If return_alternatives=True, also returns list of alternatives: [(text, confidence), ...]
    matching the scheme_data.json format: [{"text": "...", "confidence": 0.95}, ...]
    """
    start_time = time.time()

    logging.info(f"[_transcribe_whisper_ct2] model: {model}")
    logging.info(f"[_transcribe_whisper_ct2] verbose: {verbose}")
    logging.info(f"[_transcribe_whisper_ct2] return_confidence: {return_confidence}")
    logging.info(f"[_transcribe_whisper_ct2] return_alternatives: {return_alternatives}")

    try:
        if model is None:
            logging.error(f"[_transcribe_whisper_ct2] Whisper model not loaded")
            raise RuntimeError("Whisper model not loaded")

        import math

        winner_text = None
        winner_conf = 0.0
        alternatives = []

        # Handle PyTorch fallback
        if model == "pytorch_fallback":
            import librosa
            import torch

            waveform, sr = librosa.load(wav_file, sr=16000)
            inputs = processor_whisper_finetuned(waveform, sampling_rate=16000, return_tensors="pt")
            input_features = inputs.input_features.to(device)

            with torch.no_grad():
                outputs = model_whisper_finetuned_pt.generate(
                    input_features,
                    language="it",
                    task="transcribe",
                    num_beams=1,
                    num_return_sequences=1,
                    return_dict_in_generate=True,
                    output_scores=True,
                )

            decoded = processor_whisper_finetuned.batch_decode(outputs.sequences, skip_special_tokens=True)
            winner_text = (decoded[0] if decoded else "").strip()
            winner_conf = math.exp(outputs.sequences_scores[0].item()) * 100.0 if len(outputs.sequences_scores) > 0 else 0.0

            # Compute alternatives if requested
            if return_alternatives:
                try:
                    with torch.no_grad():
                        outputs_alt = model_whisper_finetuned_pt.generate(
                            input_features,
                            language="it",
                            task="transcribe",
                            num_beams=int(dpo_num_beams),
                            num_return_sequences=int(dpo_num_return_sequences),
                            return_dict_in_generate=True,
                            output_scores=True,
                        )

                    decoded_alt = processor_whisper_finetuned.batch_decode(outputs_alt.sequences, skip_special_tokens=True)
                    for txt, score in zip(decoded_alt, outputs_alt.sequences_scores):
                        alt_text = (txt or "").strip()
                        # Skip if same as winner or empty
                        if not alt_text or alt_text.lower() == winner_text.lower():
                            continue
                        alt_conf = math.exp(score.item()) * 100.0
                        alternatives.append({"text": alt_text, "confidence": round(alt_conf, 2)})
                        if len(alternatives) >= int(dpo_num_return_sequences) - 1:
                            break
                except Exception as e:
                    logging.warning(f"[_transcribe_whisper_ct2] Failed to compute alternatives: {e}")
        else:
            # faster-whisper path: first get best with beam_size=1
            segments, info = model.transcribe(
                wav_file,
                language="it",
                task="transcribe",
                beam_size=1,
                temperature=0.0,
                condition_on_previous_text=False,
            )
            segments_list = list(segments)
            winner_text = "".join([seg.text for seg in segments_list]).strip()
            if segments_list:
                avg_logprob = sum(seg.avg_logprob for seg in segments_list) / len(segments_list)
                winner_conf = math.exp(avg_logprob) * 100.0
            else:
                winner_conf = 0.0

            # Compute alternatives using temperature-based sampling if requested
            if return_alternatives:
                try:
                    sampled_candidates = []
                    for temp in dpo_sampling_temperatures:
                        for attempt in range(int(dpo_sampling_attempts_per_temperature)):
                            try:
                                segments_alt, _ = model.transcribe(
                                    wav_file,
                                    language="it",
                                    task="transcribe",
                                    beam_size=1,
                                    temperature=float(temp),
                                    condition_on_previous_text=False,
                                )
                                segments_alt_list = list(segments_alt)
                                alt_text = "".join([seg.text for seg in segments_alt_list]).strip()
                                
                                if alt_text:
                                    if segments_alt_list:
                                        avg_logprob = sum(seg.avg_logprob for seg in segments_alt_list) / len(segments_alt_list)
                                        alt_conf = math.exp(avg_logprob) * 100.0
                                    else:
                                        alt_conf = 0.0
                                    sampled_candidates.append((alt_text, alt_conf))
                            except Exception:
                                continue
                    
                    # Deduplicate and keep only alternatives different from winner
                    seen = {winner_text.lower()}
                    for alt_text, alt_conf in sampled_candidates:
                        norm_alt = alt_text.lower()
                        if norm_alt not in seen and alt_text.strip():
                            seen.add(norm_alt)
                            alternatives.append({"text": alt_text, "confidence": round(alt_conf, 2)})
                            if len(alternatives) >= int(dpo_num_return_sequences) - 1:
                                break
                except Exception as e:
                    logging.warning(f"[_transcribe_whisper_ct2] Failed to compute alternatives: {e}")

        end_time_whisper = time.time()
        if verbose:
            logging.info(f"[_transcribe_whisper_ct2] Whisper transcription took {end_time_whisper - start_time:.2f} seconds")
            logging.info(f"[_transcribe_whisper_ct2] Whisper transcript: {winner_text} (conf: {winner_conf:.1f}%)")
            if alternatives and verbose:
                for alt in alternatives:
                    logging.info(f"[_transcribe_whisper_ct2] Alternative:        {alt['text']} (conf: {alt['confidence']:.1f}%)")
            logging.info("")

        if return_alternatives:
            return (winner_text, winner_conf, alternatives) if return_confidence else (winner_text, alternatives)
        return (winner_text, winner_conf) if return_confidence else winner_text

    except Exception as e:
        tb = traceback.format_exc()
        logging.error(f"[_transcribe_whisper_ct2] Error during Whisper transcription: {e}")
        logging.error(f"[_transcribe_whisper_ct2] Traceback:\n{tb}")
        raise e

def _transcribe_whisper_ct2_pytorch(wav_file, verbose=False):
    """PyTorch fallback transcription."""
    import librosa
    import torch

    start_time = time.time()

    logging.info(f"[_transcribe_whisper_ct2_pytorch] model: {model}")
    logging.info(f"[_transcribe_whisper_ct2_pytorch] verbose: {verbose}")
    logging.info(f"[_transcribe_whisper_ct2_pytorch] return_confidence: {return_confidence}")
    logging.info(f"[_transcribe_whisper_ct2_pytorch] return_alternatives: {return_alternatives}")

    try:
        if verbose:
            logging.debug(f"[_transcribe_whisper_ct2_pytorch] Using PyTorch fallback")

        import math

        def _dedupe_candidates(cands):
            out = []
            seen_local = set()
            for txt, conf in cands:
                norm = (txt or "").strip()
                key = norm.lower()
                if not norm or key in seen_local:
                    continue
                seen_local.add(key)
                out.append((norm, conf))
            return out

        # Load audio
        waveform, sr = librosa.load(wav_file, sr=16000)

        # Process features
        inputs = processor_whisper_finetuned(waveform, sampling_rate=16000, return_tensors="pt")
        input_features = inputs.input_features.to(device)

        # Generate N-best candidates with beam search
        with torch.no_grad():
            _num_beams = int(dpo_num_beams)
            _num_return = int(dpo_num_return_sequences)
            outputs = model_whisper_finetuned_pt.generate(
                input_features,
                language="it",
                task="transcribe",
                num_beams=_num_beams,
                num_return_sequences=_num_return,
                return_dict_in_generate=True,
                output_scores=True,
            )

        sequences = outputs.sequences
        decoded = processor_whisper_finetuned.batch_decode(sequences, skip_special_tokens=True)
        
        candidates_raw = []
        for txt, score in zip(decoded, outputs.sequences_scores):
            conf = math.exp(score.item()) * 100.0
            candidates_raw.append((txt, conf))

        candidates = _dedupe_candidates(candidates_raw)

        if not candidates:
            raise RuntimeError("Whisper returned no transcription candidates")

        winner_text, winner_conf = candidates[0]
        loser_text, loser_conf = candidates[1] if len(candidates) > 1 else (None, 0.0)

        # Fallback: if beam search returns only one unique text, try sampling to get a distinct loser.
        if loser_text is None:
            sampled_raw = []
            with torch.no_grad():
                for t in dpo_sampling_temperatures:
                    for _ in range(int(dpo_sampling_attempts_per_temperature)):
                        try:
                            # Make sure sampling isn't accidentally deterministic across calls.
                            try:
                                torch.manual_seed(int(time.time() * 1000) % (2**31 - 1))
                            except Exception:
                                pass
                            out_s = model_whisper_finetuned_pt.generate(
                                input_features,
                                language="it",
                                task="transcribe",
                                do_sample=True,
                                temperature=float(t),
                                top_k=50,
                                top_p=0.95,
                                num_beams=1,
                                num_return_sequences=1,
                                return_dict_in_generate=True,
                                output_scores=True,
                            )
                            s_txt = processor_whisper_finetuned.batch_decode(out_s.sequences, skip_special_tokens=True)[0]
                            s_score = out_s.sequences_scores[0]
                            s_conf = math.exp(s_score.item()) * 100.0
                            sampled_raw.append((s_txt, s_conf))
                        except Exception as _e:
                            continue

            sampled_candidates = _dedupe_candidates(sampled_raw)
            for cand_txt, cand_conf in sampled_candidates:
                if cand_txt.strip().lower() != winner_text.strip().lower():
                    loser_text = cand_txt
                    loser_conf = cand_conf
                    break

        end_time_whisper = time.time()

        # info
        if verbose:
            logging.info(f"[_transcribe_whisper_ct2_pytorch] Whisper transcription took {end_time_whisper - start_time:.2f} seconds")

            # do not print this cause the winner was computed by the previous whisper run (before the validation)
            # here we just care about the loser            
            #logging.info(f"[_transcribe_whisper_ct2_pytorch] Whisper winner: {winner_text} (conf: {winner_conf:.1f}%)")
            
            if loser_text:
                logging.info(f"[_transcribe_whisper_ct2_pytorch] Whisper loser:  {loser_text} (conf: {loser_conf:.1f}%)")
                conf_gap = winner_conf - loser_conf
                logging.info(f"[_transcribe_whisper_ct2_pytorch] Confidence gap: {conf_gap:.1f}%")
                if conf_gap < 10.0:
                    logging.info(f"[_transcribe_whisper_ct2_pytorch] ALERT: Confidence gap < 10% (high-value sample)")
            else:
                logging.info(f"[_transcribe_whisper_ct2_pytorch] Whisper loser:  <none> (no distinct candidate)")
            logging.info("")

        # return
        return winner_text, winner_conf, loser_text, loser_conf

    except Exception as e:
        tb = traceback.format_exc()
        logging.error(f"[_transcribe_whisper_ct2_pytorch] Error during PyTorch transcription: {e}")
        logging.error(f"[_transcribe_whisper_ct2_pytorch] Traceback:\n{tb}")
        raise e

def _process_with_llm(transcript, verbose=False):
    start_time = time.time()

    prompt = llm_prompt + "The transcript is the following: " +transcript
    
    if verbose: logging.info(f"[_process_with_llm] prompt to LLM: {prompt}")
    #if verbose: logging.info(f"[_process_with_llm] Received: {transcript}")

    try:
        if verbose: logging.info(f"[_process_with_llm] Processing input with LLM...")

        # send the request to the model-server
        response: ChatResponse = chat(model=llm_model, messages=[
        {
            'role':     'user',
            'content':  prompt,
        },
        ])
        llm_response = response.message.content
        
        end_time_llm = time.time()

        # info
        if verbose:
            logging.info(f"[_process_with_llm] LLM response took {end_time_llm - start_time:.2f} seconds")
            logging.info(f"[_process_with_llm] LLM response: {llm_response}\n")
        
        # return
        return llm_response
    
    except Exception as e:
        logging.error(f"[_process_with_llm] Error during LLM response: {e}")
        raise e
