# transcribe
@app.post('/transcribe')
def transcribe(
    wav:                        UploadFile = File(...),
    folder:                     str = Query(None),  # Optional folder name from recorder
    word:                       str = Query(None),  # Optional word being recorded
    index:                      int = Query(None),  # Optional index in recording session
    audio_source:               str = Query("dgx"),  # Source of audio (dgx, frontend, whatsapp)
    upload_to_firebase_server:  bool = Query(True),
    process_with_llm:           bool = Query(False),
    return_alternatives:        bool = Query(False),
    json_response:              bool = Query(False),
    request:                    Request = None,
):
    logging.info(f"[transcribe] Received request. Processing...")
    logging.info(f"[transcribe] folder: {folder}")
    logging.info(f"[transcribe] word: {word}")
    logging.info(f"[transcribe] index: {index}")
    logging.info(f"[transcribe] audio_source: {audio_source}")
    logging.info(f"[transcribe] upload_to_firebase_server: {upload_to_firebase_server}")
    logging.info(f"[transcribe] process_with_llm: {process_with_llm}")
    logging.info(f"[transcribe] return_alternatives: {return_alternatives}")
    logging.info(f"[transcribe] json_response: {json_response}")

    start_time = time.time()    
  
    # transcribe with Whisper model
    try:
        # process input wav file
        wav_file = _process_wavfile(wav)

        if return_alternatives:
            transcript_whisper, whisper_conf, alternatives = _transcribe_whisper_ct2(
                wav_file,
                model_whisper_finetuned,
                verbose=verbose,
                return_confidence=True,
                return_alternatives=True,
            )
        else:
            transcript_whisper, whisper_conf = _transcribe_whisper_ct2(
                wav_file,
                model_whisper_finetuned,
                verbose=verbose,
                return_confidence=True,
                return_alternatives=False,
            )
            alternatives = []

        transcript = transcript_whisper
    except Exception as e:
        tb = traceback.format_exc()
        logging.error(f"[transcribe] Error during transcription: {e}")
        logging.error(f"[transcribe] Traceback:\n{tb}")
        return JSONResponse(content={"error": str(e), "traceback": tb}, status_code=500)

    # process with LLM
    llm_available = False
    try:
        if process_with_llm:
            logging.info(f"[transcribe] Calling LLM...")
            if llm_response := _process_with_llm(transcript, verbose=verbose):
                transcript = llm_response
                llm_available = True
            else:
                logging.warning("[transcribe] LLM response is empty. Keeping original transcript.")
    except Exception as e:
        tb = traceback.format_exc()
        logging.error(f"[transcribe] Error during LLM processing: {e}")
        logging.error(f"[transcribe] Traceback:\n{tb}")

    # finalize
    end_time = time.time()
    if verbose:
        logging.info(f"[transcribe] Total required time: {end_time - start_time:.2f} seconds")
        logging.info(f"[transcribe] Final transcript: {transcript}")

    # store received audio to Firebase Storage
    firebase_audio_file = None
    entry_id = None
    if upload_to_firebase_server:
        # Use provided folder name or generate default
        if folder:
            firebase_folder = folder
        elif llm_available:
            firebase_folder = f"{datetime.now().strftime('%Y%m%d')}_dgx-whisper-llm"
        else:
            firebase_folder = f"{datetime.now().strftime('%Y%m%d')}_dgx-whisper"
        
        folder_result, file_index = _upload_to_firebase(wav_file, transcript, firebase_folder, verbose=verbose)

        # Cache metadata for later validation.
        if folder_result and file_index:
            firebase_audio_file = f"{folder_result}/{file_index}.wav"
            device_key = None
            try:
                device_key = request.headers.get("X-Device-Id") if request else None
            except Exception:
                device_key = None
            if not device_key:
                try:
                    device_key = request.client.host if request and request.client else "unknown"
                except Exception:
                    device_key = "unknown"

            # Compute audio duration
            try:
                import wave
                with wave.open(wav_file, 'rb') as wf:
                    audio_duration = wf.getnframes() / wf.getframerate()
            except Exception:
                audio_duration = 0.0

            # Generate unique interaction ID and timestamp
            entry_id = str(uuid.uuid4())
            entry_timestamp = datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")

            # Set model version in the interaction entry. If LLM processing was applied, append the LLM model name to the base Whisper model version for clarity.
            model_version = path_whisper_finetuned
            if llm_available:
                model_version = path_whisper_finetuned + " + " + llm_model

            # Create chiara-speech2text_scheme_data entry (user_validated=False initially)
            entry_entry = _build_entry_entry(
                entry_id=entry_id,
                timestamp=entry_timestamp,
                audio_file=f"{file_index}.wav",
                audio_duration=audio_duration,
                transcript=(transcript or "").strip(),
                confidence=whisper_conf,
                model_version=model_version,
                user_validated=False,
                alternatives=alternatives,
                audio_source=audio_source,  # Pass the audio source
            )
            _add_interaction(folder_result, entry_entry, verbose=verbose)

            with LATEST_BY_DEVICE_LOCK:
                LATEST_BY_DEVICE[device_key] = {
                    "ts":           time.time(),
                    "folder":       firebase_folder,
                    "audio_file":   firebase_audio_file,
                    "duration":     audio_duration,
                    "text":         (transcript or "").strip(),
                    "confidence":   whisper_conf,
                    "entry_id": entry_id,
                    "alternatives":  alternatives,
                }
            if verbose:
                logging.info(
                    f"[transcribe] Cached validation entry for device_key={device_key} audio_file={firebase_audio_file} entry_id={entry_id}"
                )
        else:
            if verbose:
                logging.info("[transcribe] Firebase upload failed; skipping validation cache")
    else:
        if verbose: logging.info(f"[transcribe] Skipping upload to Firebase as per request parameter")

    # remove audio file
    try:                os.remove(wav_file)
    except Exception:   pass

    # prepare response payload
    response_payload = {
        "transcript": transcript,
        "whisper_confidence": round(whisper_conf, 2),
        "whisper_model": path_whisper_finetuned,
        "alternatives": alternatives if return_alternatives else [],
        "entry_id": entry_id,
        "status": "success",
    }

    # return json response
    if json_response: return JSONResponse(content=response_payload)
    
    # default: return plain text when json_response is False
    return PlainTextResponse(content=transcript)

# validate endpoint
@app.post("/validate")
def validate(request_body: ValidateRequest, request: Request):
    device_key = None
    try:
        device_key = request.headers.get("X-Device-Id")
    except Exception:
        device_key = None
    if not device_key:
        try:
            device_key = request.client.host if request.client else "unknown"
        except Exception:
            device_key = "unknown"

    with LATEST_BY_DEVICE_LOCK:
        entry = LATEST_BY_DEVICE.get(device_key)
    now = time.time()
    if not entry:
        logging.info(f"[validate] No pending entry for device_key={device_key}")
        return JSONResponse(content={"status": "noop", "reason": "no_pending"}, status_code=200)

    age = now - float(entry.get("ts", 0.0))
    if age > float(validated_data_ttl_sec):
        logging.info(f"[validate] Stale validation for device_key={device_key} age_sec={age:.1f}; ignoring")
        with LATEST_BY_DEVICE_LOCK:
            try:
                del LATEST_BY_DEVICE[device_key]
            except KeyError:
                pass
        return JSONResponse(content={"status": "noop", "reason": "stale"}, status_code=200)

    received = (request_body.transcript or "").strip().lower()
    expected = (entry.get("text") or "").strip().lower()
    logging.info(f"[validate] Received: {received}")
    logging.info(f"[validate] Expected: {expected}")
    if received != expected:
        logging.info(f"[validate] Transcript mismatch for device_key={device_key}; ignoring")
        return JSONResponse(content={"status": "noop", "reason": "mismatch"}, status_code=200)

    # Extract audio file index (needed for background processing)
    audio_file = entry.get("audio_file")
    file_index = None
    try:
        if audio_file:
            file_index = int(os.path.splitext(os.path.basename(audio_file))[0])
    except Exception:
        file_index = None

    # Remove the entry immediately (idempotent validation).
    with LATEST_BY_DEVICE_LOCK:
        try:
            del LATEST_BY_DEVICE[device_key]
        except KeyError:
            pass

    # Mark interaction as user_validated=true in data.json
    entry_id = entry.get("entry_id")
    folder = entry.get("folder", "")
    if entry_id and folder:
        updates = {"user_validated": True}

        # If alternatives were computed and cached during transcription (unlikely now), add them.
        cached_alternatives = entry.get("alternatives", []) or []
        if cached_alternatives:
            updates["inference_alternative_transcript"] = cached_alternatives
            if verbose:
                logging.info(f"[validate] Adding {len(cached_alternatives)} cached alternative(s) to interaction {entry_id}")

        _update_interaction(folder, entry_id, updates, verbose=verbose)
        logging.info(f"[validate] Marked interaction {entry_id} as user_validated in {folder}/data.json")

        # If no alternatives available yet, queue background computation (won't block response)
        if not cached_alternatives and file_index is not None:
            try:
                VALIDATION_EXECUTOR.submit(
                    _compute_and_upload_alternatives_in_background,
                    device_key,
                    folder,
                    int(file_index),
                    entry_id,
                    (entry.get("text") or "").strip(),
                    verbose,
                )
                logging.info(f"[validate] Queued background alternative computation for {folder}/{file_index} interaction {entry_id}")
                return JSONResponse(content={"status": "ok", "queued": True}, status_code=200)
            except Exception as e:
                logging.error(f"[validate] Failed to queue background job: {e}")
                return JSONResponse(content={"status": "error", "reason": "queue_failed"}, status_code=500)

    logging.info(f"[validate] Validation complete for device_key={device_key} audio_file={entry.get('audio_file')}")
    return JSONResponse(content={"status": "ok"}, status_code=200)

# llm endpoint
@app.post('/llm')
def process_llm(request: LLMRequest):
    start_time = time.time()
    
    try:
        if verbose:
            logging.info(f"[/llm] Processing request with model: {llm_model}")
            logging.info(f"[/llm] Received messages: {request.messages}")
        
        # send the request to the ollama model
        response: ChatResponse = chat(model=llm_model, messages=request.messages)
        llm_response = response.message.content
        
        end_time = time.time()
        
        # info
        if verbose:
            logging.info(f"[/llm] LLM response took {end_time - start_time:.2f} seconds")
            logging.info(f"[/llm] Response: {llm_response}")
        
        # return
        return PlainTextResponse(content=llm_response)
    
    except Exception as e:
        logging.error(f"[/llm] Error: {e}")
        return JSONResponse(content={"error": str(e)}, status_code=500)

